mapper.select:
select main_currency, sum(bet_amount) as totalBetAmount, sum(valid_bet_amount) as validAmount, sum(bet_win_lose) as betWinLoss, sum(bet_win_lose)+sum(already_use_amount) as totalWinLoss, sum(rebate_amount) as totalRebate, sum(activity_amount) as totalDiscount, sum(adjust_amount) as accountAdjust from report_user_win_lose where 1 = 1
AND super_agent_account IN
#{value}
AND day_hour_millis >= #{vo.startTime}
AND day_hour_millis <= #{vo.endTime}
and site_code = #{vo.siteCode}
group by main_currency

select
sum(t.valid_bet_amount) as validAmount,
t.user_account as userAccount
from report_user_win_lose t left join user_info t1
on t.super_agent_account = t1.super_agent_account and t.user_account = t1.user_account
where 1 = 1

    AND t1.super_agent_id IN

        #{value}



    AND t.day_hour_millis  >=  #{vo.startTime}


    AND t.day_hour_millis  <=  #{vo.endTime}



    and site_code = #{siteCode}

group by t.user_account

select
IFNULL(sum(t.bet_win_lose), 0) as amount,
t.super_agent_account as agentAccount,
t.main_currency as currency
from report_user_win_lose t
where
    1 = 1

    AND t.super_agent_account in

        #{value}



    AND t.agent_id in

        #{agentId}



    AND t.day_hour_millis  >=  #{vo.startTime}


    AND t.day_hour_millis  <=  #{vo.endTime}


    and site_code = #{vo.siteCode}


    and main_currency = #{vo.currency}

group by t.super_agent_account, t.main_currency

select
a.userAccount,
c.agent_account as superAgentAccount
from (
SELECT
user_account AS userAccount,
sum(valid_bet_amount) as validBetAmount,
super_agent_account as superAgentAccount
FROM
report_user_win_lose
WHERE
day_hour_millis   >=  #{start}
AND day_hour_millis  <=  #{end}
and super_agent_account is not null

    and agent_id in

        #{value}



    and site_code = #{siteCode}

group by user_account, super_agent_account
)a, agent_info c where a.superAgentAccount = c.agent_account
AND a.validBetAmount  >=  #{activeBet}

SELECT b.userAccount AS userAccount , c.agent_account as superAgentAccount FROM ( SELECT a.userAccount, sum( a.amount ) AS resultAmount FROM ( SELECT user_account AS userAccount, SUM( adjust_amount ) AS amount FROM user_manual_up_down_record WHERE adjust_way = 1 AND adjust_type = 3 AND audit_status = 3
and agent_account in
#{value}
AND updated_time >= #{start} AND updated_time <= #{end} GROUP BY user_account UNION ( SELECT user_account AS userAccount, SUM( arrive_amount ) AS amount FROM user_deposit_withdrawal WHERE type = 1
and agent_account in
#{value}
AND updated_time >= #{start} AND updated_time <= #{end} AND STATUS = 101 GROUP BY user_account ) UNION ( SELECT user_account AS userAccount, SUM( amount ) AS amount FROM agent_deposit_subordinates WHERE 1 = 1
and agent_account in
#{value}
AND deposit_time >= #{start} AND deposit_time <= #{end} GROUP BY user_account ) ) a GROUP BY a.userAccount ) b, user_info t, agent_info c WHERE b.userAccount = t.user_account and t.super_agent_account = c.agent_account AND t.super_agent_account is not null and b.resultAmount >= #{activeDeposit}

SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(`day_millis`/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') myDay, main_currency as currencyCode, IFNULL(sum( bet_win_lose ), 0) betWinLose, IFNULL(sum( valid_bet_amount ), 0) validBetAmount FROM report_user_win_lose
AND agent_id = #{agentId}
AND main_currency = #{currencyCode}
AND `day_hour_millis` >= #{start}
AND `day_hour_millis` <= #{end}
GROUP BY DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(`day_millis`/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d'),main_currency ORDER BY myDay ASC

SELECT user_id userId, main_currency as currency, IFNULL(sum( bet_win_lose ), 0) winLossAmount, IFNULL(sum( valid_bet_amount ), 0) validAmount FROM report_user_win_lose
and agent_id in
#{value}
AND `day_hour_millis` >= #{vo.startTime}
AND `day_hour_millis` <= #{vo.endTime}
