SELECT
MONTH(CONVERT_TZ(FROM_UNIXTIME(`day_millis`/1000), @@session.time_zone, #{dbZone})) myDay,
main_currency as currencyCode,
IFNULL(sum( bet_win_lose ), 0) betWinLose
