SELECT main_currency as currencyCode, IFNULL(sum( a.bet_win_lose ), 0) betWinLose, IFNULL(sum(a.bet_win_lose)-sum(a.already_use_amount), 0) profitAndLoss FROM report_user_win_lose a
AND site_code = #{siteCode}
AND `day_hour_millis` >= #{start}
AND `day_hour_millis` <= #{end}
and account_type=2
GROUP BY currencyCode

SELECT any_value ( user_account ) userAccount, user_id as userId, IFNULL(sum( bet_win_lose ), 0) betWinLose, IFNULL(sum(a.bet_win_lose)+sum(a.already_use_amount)+sum(a.adjust_amount)-sum(a.tips_amount), 0) profitAndLoss, IFNULL(sum( activity_amount ), 0) activityAmount, IFNULL(sum( vip_amount ), 0) vipAmount, IFNULL(sum( already_use_amount ), 0) alreadyUseAmount, IFNULL(sum( rebate_amount ), 0) rebateAmount, IFNULL(sum( valid_bet_amount ), 0) validBetAmount, IFNULL(sum( bet_amount ), 0) betAmount, IFNULL(sum( tips_amount ), 0) tipsAmount, IFNULL(sum( adjust_amount ), 0) adjustAmount FROM report_user_win_lose a
AND agent_id = #{agentId}
AND user_id = #{userId}
AND `day_hour_millis` >= #{start}
AND `day_hour_millis` <= #{end}
GROUP BY user_id

SELECT abc.userId userId, abc.userAccount userAccount, abc.userName userName, abc.accountType accountType, cc.super_agent_account superAgentAccount, cc.agent_attribution agentAttribution, abc.vipGradeCode vipGradeCode, abc.vipRankCode vipRankCode, abc.accountStatus accountStatus, abc.userLabelId userLabelId, abc.riskLevelId riskLevelId, abc.mainCurrency mainCurrency, abc.betNum betNum, abc.betAmount betAmount, abc.validBetAmount validBetAmount, abc.runWaterCorrect runWaterCorrect, abc.betWinLose betWinLose, abc.activityAmount activityAmount, abc.alreadyUseAmount alreadyUseAmount, abc.rebateAmount rebateAmount, abc.vipAmount vipAmount, abc.adjustAmount adjustAmount, abc.repairOrderOtherAdjust repairOrderOtherAdjust, abc.platAdjustAmount platAdjustAmount, abc.tipsAmount tipsAmount, abc.riskAmount riskAmount, abc.profitAndLoss profitAndLoss FROM ( SELECT a.user_id userId, max(a.id) id, any_value(b.user_name) userName, any_value ( b.user_account ) userAccount, any_value(b.account_type) accountType, any_value(b.vip_grade_code) vipGradeCode, any_value(b.vip_rank) vipRankCode, any_value(b.account_status) accountStatus, any_value(b.user_label_id) userLabelId, any_value(b.risk_level_id) riskLevelId, any_value(b.main_currency) mainCurrency, sum(a.bet_num) betNum, sum(a.bet_amount) betAmount, sum(a.valid_bet_amount) validBetAmount, sum(a.run_water_correct) runWaterCorrect, sum(a.bet_win_lose) betWinLose, sum(a.activity_amount) activityAmount, sum(a.already_use_amount) alreadyUseAmount, sum(a.rebate_amount) rebateAmount, sum(a.vip_amount) vipAmount, sum(a.adjust_amount) adjustAmount, IFNULL(SUM(a.repair_order_other_adjust), 0) repairOrderOtherAdjust, sum(a.plat_adjust_amount) platAdjustAmount, sum(a.tips_amount) tipsAmount, sum(a.risk_amount) riskAmount, sum(a.bet_win_lose)+sum(a.already_use_amount)-sum(a.tips_amount)+sum(a.adjust_amount) profitAndLoss FROM report_user_win_lose a LEFT JOIN user_info b ON a.user_id = b.user_id
AND a.day_hour_millis >= #{vo.startDay}
AND a.day_hour_millis <= #{vo.endDay}
AND a.user_account = #{vo.userAccount}
AND a.site_code = #{vo.siteCode}
AND a.super_agent_account = #{vo.superAgentAccount}
AND a.main_currency = #{vo.mainCurrency}
AND b.account_type = #{vo.accountType}
AND a.agent_attribution = #{vo.agentAttribution}
GROUP BY a.user_id,a.agent_id ) abc LEFT JOIN ( SELECT id,super_agent_account,agent_attribution FROM report_user_win_lose ) cc on abc.id = cc.id
AND abc.betNum >= #{vo.betNumMin}
AND abc.betNum <= #{vo.betNumMax}
AND abc.betAmount >= #{vo.betAmountMin}
AND abc.betAmount <= #{vo.betAmountMax}
AND abc.betWinLose >= #{vo.betWinLoseMin}
AND abc.betWinLose <= #{vo.betWinLoseMax}
AND abc.profitAndLoss >= #{vo.profitAndLossMin}
AND abc.profitAndLoss <= #{vo.profitAndLossMax}
ORDER BY betNum asc
ORDER BY betNum desc
ORDER BY betAmount asc
ORDER BY betAmount desc
ORDER BY validBetAmount asc
ORDER BY validBetAmount desc
ORDER BY runWaterCorrect asc
ORDER BY runWaterCorrect desc
ORDER BY betWinLose asc
ORDER BY betWinLose desc
ORDER BY rebateAmount asc
ORDER BY rebateAmount desc
ORDER BY activityAmount asc
ORDER BY activityAmount desc
ORDER BY alreadyUseAmount asc
ORDER BY alreadyUseAmount desc
ORDER BY vipAmount asc
ORDER BY vipAmount desc
ORDER BY adjustAmount asc
ORDER BY adjustAmount desc
ORDER BY repairOrderOtherAdjust asc
ORDER BY repairOrderOtherAdjust desc
ORDER BY profitAndLoss asc
ORDER BY profitAndLoss desc
ORDER BY tipsAmount asc
ORDER BY tipsAmount desc
ORDER BY platAdjustAmount asc
ORDER BY platAdjustAmount desc
ORDER BY riskAmount asc
ORDER BY riskAmount desc
ORDER BY abc.betWinLose DESC, abc.validBetAmount DESC, abc.betNum DESC ,abc.userAccount

SELECT
count(1)
FROM (
SELECT
a.user_id userId,
max(a.id) id,
any_value(b.user_name) userName,
any_value ( b.user_account ) userAccount,
any_value(b.account_type) accountType,
any_value(b.vip_grade_code) vipGradeCode,
any_value(b.account_status) accountStatus,
any_value(b.user_label_id) userLabelId,
any_value(b.risk_level_id) riskLevelId,
any_value(b.main_currency) mainCurrency,
sum(a.bet_num) betNum,
sum(a.bet_amount) betAmount,
sum(a.valid_bet_amount) validBetAmount,
sum(a.run_water_correct) runWaterCorrect,
sum(a.bet_win_lose) betWinLose,
sum(a.activity_amount) activityAmount,
sum(a.already_use_amount) alreadyUseAmount,
sum(a.rebate_amount) rebateAmount,
sum(a.vip_amount) vipAmount,
sum(a.adjust_amount) adjustAmount,
IFNULL(SUM(a.repair_order_other_adjust), 0) repairOrderOtherAdjust,
sum(a.plat_adjust_amount) platAdjustAmount,
sum(a.tips_amount) tipsAmount,
sum(a.risk_amount) riskAmount,
sum(a.bet_win_lose)+sum(a.already_use_amount)-sum(a.tips_amount)+sum(a.risk_amount) profitAndLoss
FROM report_user_win_lose a
LEFT JOIN user_info b ON a.user_id = b.user_id


        AND a.day_hour_millis  >=  #{vo.startDay}


        AND a.day_hour_millis  <=  #{vo.endDay}


        AND a.user_account = #{vo.userAccount}


        AND a.site_code = #{vo.siteCode}


        AND a.super_agent_account = #{vo.superAgentAccount}


        AND a.main_currency = #{vo.mainCurrency}


        AND b.account_type = #{vo.accountType}


        AND a.agent_attribution = #{vo.agentAttribution}



GROUP BY a.user_id,a.agent_id
) abc

LEFT JOIN ( SELECT id,super_agent_account,agent_attribution FROM report_user_win_lose ) cc on abc.id = cc.id


        AND abc.betNum  >=  #{vo.betNumMin}


        AND abc.betNum  <=  #{vo.betNumMax}


        AND abc.betAmount  >=  #{vo.betAmountMin}


        AND abc.betAmount  <=  #{vo.betAmountMax}


        AND abc.betWinLose  >=  #{vo.betWinLoseMin}


        AND abc.betWinLose  <=  #{vo.betWinLoseMax}


        AND abc.profitAndLoss  >=  #{vo.profitAndLossMin}


        AND abc.profitAndLoss  <=  #{vo.profitAndLossMax}

SELECT 'all' userId, mainCurrency mainCurrency, IFNULL(SUM(abc.betNum), 0) betNum, IFNULL(SUM(abc.betAmount), 0) betAmount, IFNULL(SUM(abc.validBetAmount), 0) validBetAmount, IFNULL(SUM(abc.runWaterCorrect), 0) runWaterCorrect, IFNULL(SUM(abc.betWinLose), 0) betWinLose, IFNULL(SUM(abc.rebateAmount), 0) rebateAmount, IFNULL(SUM(abc.activityAmount), 0) activityAmount, IFNULL(SUM(abc.alreadyUseAmount), 0) alreadyUseAmount, IFNULL(SUM(abc.vipAmount), 0) vipAmount, IFNULL(SUM(abc.adjustAmount), 0) adjustAmount, IFNULL(SUM(abc.repairOrderOtherAdjust), 0) repairOrderOtherAdjust, IFNULL(SUM(abc.platAdjustAmount), 0) platAdjustAmount, IFNULL(SUM(abc.tipsAmount), 0) tipsAmount, IFNULL(SUM(abc.riskAmount), 0) riskAmount, IFNULL(SUM(abc.profitAndLoss), 0) profitAndLoss FROM ( SELECT a.user_id userId, a.main_currency mainCurrency, max(a.id) id, sum(a.bet_num) betNum, sum(a.bet_amount) betAmount, sum(a.valid_bet_amount) validBetAmount, sum(a.run_water_correct) runWaterCorrect, sum(a.bet_win_lose) betWinLose, sum(a.rebate_amount) rebateAmount, sum(a.activity_amount) activityAmount, sum(a.already_use_amount) alreadyUseAmount, sum(a.vip_amount) vipAmount, sum(a.adjust_amount) adjustAmount, sum(a.repair_order_other_adjust) repairOrderOtherAdjust, sum(a.plat_adjust_amount) platAdjustAmount, sum(a.tips_amount) tipsAmount, sum(a.risk_amount) riskAmount, sum(a.bet_win_lose)+sum(a.already_use_amount)-sum(a.tips_amount)+sum(a.adjust_amount) profitAndLoss FROM report_user_win_lose a LEFT JOIN user_info b ON a.user_id = b.user_id
AND a.day_hour_millis >= #{vo.startDay}
AND a.day_hour_millis <= #{vo.endDay}
AND a.user_account = #{vo.userAccount}
AND a.site_code = #{vo.siteCode}
AND a.super_agent_account = #{vo.superAgentAccount}
AND b.account_type = #{vo.accountType}
AND b.main_currency = #{vo.mainCurrency}
AND a.agent_attribution = #{vo.agentAttribution}
GROUP BY a.user_id ,a.main_currency ) abc
AND abc.betNum >= #{vo.betNumMin}
AND abc.betNum <= #{vo.betNumMax}
AND abc.betAmount >= #{vo.betAmountMin}
AND abc.betAmount <= #{vo.betAmountMax}
AND abc.betWinLose >= #{vo.betWinLoseMin}
AND abc.betWinLose <= #{vo.betWinLoseMax}
AND abc.profitAndLoss >= #{vo.profitAndLossMin}
AND abc.profitAndLoss <= #{vo.profitAndLossMax}
Group by mainCurrency

