sum(a.already_use_amount) alreadyUseAmount,
sum(a.vip_amount) vip_amount,
sum(a.adjust_amount) adjustAmount,
sum(a.plat_adjust_amount) platAdjustAmount,
sum(a.tips_amount) tipsAmount,
sum(a.risk_amount) riskAmount,
sum(a.bet_win_lose)+sum(a.already_use_amount)-sum(a.tips_amount)+sum(a.risk_amount) profitAndLoss
