SELECT day_millis, count(distinct if(bet_num > 0, user_id, null)) betMemNum, IFNULL(sum(a.bet_num),0) betNum, IFNULL(sum(a.bet_amount),0) betAmount, IFNULL(sum(a.valid_bet_amount),0) validBetAmount, IFNULL(sum(a.run_water_correct),0) runWaterCorrect, IFNULL(sum(a.bet_win_lose),0) betWinLose, IFNULL(sum(a.rebate_amount),0) rebateAmount, IFNULL(sum(a.activity_amount),0) activityAmount, IFNULL(sum(a.vip_amount),0) vipAmount, IFNULL(sum(a.adjust_amount),0) adjustAmount, IFNULL(sum(a.repair_order_other_adjust), 0) repairOrderOtherAdjust, IFNULL(sum(a.already_use_amount),0) alreadyUseAmount, IFNULL(sum(a.rebate_amount),0) rebate_amount, IFNULL(sum(a.plat_adjust_amount),0) platAdjustAmount, IFNULL(sum(a.tips_amount),0) tipsAmount, a.main_currency mainCurrency FROM report_user_win_lose a
a.site_code = #{siteCode}
AND a.day_hour_millis >= #{vo.startDay}
AND a.day_hour_millis <= #{vo.endDay}
AND a.main_currency = #{vo.mainCurrency}
GROUP BY day_millis,main_currency

SELECT dayStr, mm.main_currency, IFNULL( sum( valid_bet_amount ), 0 ) validBetAmount, IFNULL( sum( bet_win_lose ), 0 ) betWinLose, -(IFNULL( sum( bet_win_lose ), 0 ) + IFNULL( sum( tips_amount ), 0 ) - IFNULL( sum( already_use_amount ), 0 ) - IFNULL( sum( adjust_amount ), 0 )) profitAndLoss FROM (
SELECT DATE_FORMAT( CONVERT_TZ( FROM_UNIXTIME( day_millis / 1000 ), @@SESSION.time_zone, #{vo.timezone}), '%Y-%m-%d' ) AS dayStr, IFNULL( a.valid_bet_amount, 0 ) valid_bet_amount, IFNULL( a.bet_win_lose, 0 ) bet_win_lose, IFNULL( a.tips_amount, 0 ) tips_amount, IFNULL( a.already_use_amount, 0 ) already_use_amount, IFNULL( a.adjust_amount, 0 ) adjust_amount, a.main_currency FROM report_user_win_lose a
a.site_code = #{vo.siteCode}
and a.user_id = #{vo.userId}
AND a.day_millis >= #{vo.startTime}
AND a.day_millis <= #{vo.endTime}
AND a.main_currency = #{vo.currencyCode}
) mm GROUP BY dayStr,main_currency

SELECT
COUNT( 1 )
FROM
(
SELECT
main_currency
FROM report_user_win_lose a

    a.site_code = #{siteCode}

        AND a.day_hour_millis  >=  #{vo.startDay}


        AND a.day_hour_millis  <=  #{vo.endDay}



        AND a.main_currency = #{vo.mainCurrency}


GROUP BY day_millis,main_currency
) b

SELECT day_millis AS dayMillis, any_value(a.super_agent_account) superAgentAccount, any_value(a.main_currency) mainCurrency, sum(a.bet_num) betNum, sum(a.bet_amount) betAmount, sum(a.valid_bet_amount) validBetAmount, sum(a.run_water_correct) runWaterCorrect, sum(a.bet_win_lose) betWinLose, sum(a.rebate_amount) rebateAmount, sum(a.activity_amount) activityAmount, sum(a.already_use_amount) alreadyUseAmount, sum(a.vip_amount) vipAmount, sum(a.adjust_amount) adjustAmount, sum(a.bet_win_lose)+sum(a.already_use_amount) -sum(a.tips_amount)+sum(a.adjust_amount) profitAndLoss, sum(a.plat_adjust_amount) platAdjustAmount, sum(a.tips_amount) tipsAmount, sum(a.risk_amount) riskAmount FROM report_user_win_lose a
AND a.day_hour_millis >= #{vo.startDay}
AND a.day_hour_millis <= #{vo.endDay}
AND a.user_account = #{vo.userAccount}
AND a.site_code = #{vo.siteCode}
AND a.super_agent_account = #{vo.superAgentAccount}
AND a.super_agent_account IS NULL
group by dayMillis ORDER BY dayMillis

SELECT t.main_currency, t.user_id,ANY_VALUE(t.user_account) user_account, SUM(t.valid_bet_amount) AS
validBetAmount
FROM report_user_win_lose t
WHERE
t.site_code = #{siteCode}

    AND t.day_hour_millis  >=  #{firstDayMilli}


    AND t.day_hour_millis  <=  #{lastDayMilli}

GROUP BY t.main_currency, t.user_id
HAVING validBetAmount > 0 and validBetAmount = (
SELECT MAX(valid_bet_amount)
FROM (
SELECT SUM(valid_bet_amount) AS valid_bet_amount
FROM report_user_win_lose
WHERE
site_code = #{siteCode}
AND main_currency = t.main_currency

    AND day_hour_millis  >=  #{firstDayMilli}


    AND day_hour_millis  <=  #{lastDayMilli}

GROUP BY user_id
) AS sub
);

SELECT t.main_currency, t.user_id,ANY_VALUE(t.user_account) user_account, SUM(t.bet_win_lose) AS betWinLose
FROM report_user_win_lose t
WHERE
t.site_code = #{siteCode}

