HAVING betWinLose  <  0 and betWinLose = (
SELECT MIN(bet_win_lose)
FROM (
SELECT SUM(bet_win_lose) AS bet_win_lose
FROM report_user_win_lose
WHERE
site_code = #{siteCode}
AND main_currency = t.main_currency

    AND day_hour_millis  >=  #{firstDayMilli}


    AND day_hour_millis  <=  #{lastDayMilli}

GROUP BY user_id
) AS sub
);

